INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '34f371e2-8c67-4c85-8ab9-078dc5f26c98',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Networking — Why Your VPC Is Global But Your Subnets Aren't$escape$,
  $escape$GCP VPCs are global resources — a single VPC spans all regions, unlike AWS where VPCs are region-scoped. Subnets are regional, so one VPC can have a subnet in us-central1 and another in europe-west1, communicating over Google's private backbone with no peering required.

Firewall rules are VPC-scoped, not subnet-scoped, and they target VMs via network tags or service accounts — not security group IDs. A rule allowing tcp:8080 from tag `frontend` to tag `backend` applies across every subnet in the VPC, in every region.

For Private Google Access, enable it per-subnet so VMs without external IPs can reach Google APIs (BigQuery, GCS, Pub/Sub) via private.googleapis.com. Without it, those VMs need Cloud NAT or a public IP to egress.

Cloud DNS private zones are VPC-bound. Cross-project resolution requires DNS peering (not VPC peering) — a common footgun. Always use custom-mode VPCs in production; auto-mode creates a /20 in every region automatically, which collides with on-prem CIDR ranges fast.$escape$,
  $escape$# Never use auto-mode in prod — subnets in every region by default
gcloud compute networks create prod-vpc \
  --subnet-mode=custom \
  --bgp-routing-mode=global

# Regional subnet with Private Google Access enabled
gcloud compute networks subnets create prod-subnet-us \
  --network=prod-vpc \
  --region=us-central1 \
  --range=10.0.0.0/20 \
  --enable-private-ip-google-access

# Firewall rule scoped by network tag, not subnet
gcloud compute firewall-rules create allow-backend \
  --network=prod-vpc \
  --allow=tcp:8080 \
  --source-tags=frontend \
  --target-tags=backend$escape$,
