INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8a645bb8-2735-47c4-a526-8e4349d96301',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Storage — Object vs Block vs File: Picking the Right One$escape$,
  $escape$GCP gives you three storage primitives and conflating them is expensive. Cloud Storage (GCS) is object storage — globally durable, infinitely scalable, accessed over HTTP. Use it for assets, backups, data lake raw zones, and ML training datasets. It has no filesystem semantics; you GET/PUT by key. Persistent Disk (PD) and Hyperdisk are block storage — low-latency SSD volumes attached to Compute Engine or GKE nodes. Use them for databases (Postgres, MySQL), stateful containers, and OS boot volumes. Hyperdisk Extreme hits 350,000 IOPS for latency-sensitive workloads. Filestore is managed NFS — a fully POSIX-compliant shared filesystem. Use it when multiple GKE pods or VMs need concurrent read/write access to the same directory tree (e.g., shared ML checkpoints, CMS media mounts). The decision tree: serving static bytes to the internet → GCS; running a database on a VM → PD/Hyperdisk; shared mounts across multiple nodes → Filestore. Mixing them up (e.g., using Filestore for cold backups) is wasteful — GCS at Nearline tier costs ~70% less per GB.$escape$,
  $escape$# Object: upload to GCS bucket
gsutil cp model_weights.bin gs://my-ml-bucket/checkpoints/

# Block: create a Hyperdisk Extreme PD and attach to a VM
gcloud compute disks create db-volume \
  --type=hyperdisk-extreme \
  --size=500GB \
  --provisioned-iops=100000 \
  --zone=us-central1-a

gcloud compute instances attach-disk my-db-vm \
  --disk=db-volume --zone=us-central1-a

# File: create a Filestore instance for shared NFS mount
gcloud filestore instances create shared-fs \
  --tier=BASIC_SSD --file-share=name=data,capacity=1TB \
  --network=name=default --zone=us-central1-a$escape$,
  $escape$bash$escape$,
