INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '83e29e11-7e40-4aa1-973a-25d3f72728e0',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Cloud SQL — Managed Databases, Read Replicas, and Automated Backups$escape$,
  $escape$Cloud SQL is GCP's fully managed relational database service supporting PostgreSQL, MySQL, and SQL Server. Instances run on Compute Engine under the hood, but Google handles patching, replication, and storage scaling. For read-heavy workloads, Cloud SQL supports cross-region read replicas — promoted to primary in under 60 seconds during failover. Replicas are created via `gcloud sql instances create` with `--master-instance-name` and `--replica-type=READ`. Point-in-time recovery (PITR) uses binary logs (MySQL) or WAL (PostgreSQL) to restore to any second within the retention window. Automated backups run on a configurable schedule and are stored in Cloud Storage, billed separately from instance storage. For high availability, enable the HA configuration which provisions a standby in a different zone with synchronous replication — failover is automatic and typically completes in under 35 seconds. Cloud SQL Auth Proxy (`cloud-sql-proxy`) handles IAM-based mTLS connections without exposing public IPs, replacing password-based access in production.$escape$,
  $escape$# Create a PostgreSQL Cloud SQL instance with HA and automated backups
gcloud sql instances create prod-db \
  --database-version=POSTGRES_15 \
  --tier=db-custom-4-16384 \
  --region=us-central1 \
  --availability-type=REGIONAL \
  --backup-start-time=03:00 \
  --retained-backups-count=14 \
  --enable-point-in-time-recovery

# Add a cross-region read replica
gcloud sql instances create prod-db-replica \
  --master-instance-name=prod-db \
  --replica-type=READ \
  --region=us-east1$escape$,
  $escape$bash$escape$,
