INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f24b9374-c4b5-4a04-a26e-843c83a04365',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Cost Optimization — Reserved, Spot, and On-Demand VMs with Budget Guardrails$escape$,
  $escape$GCP's three compute pricing tiers serve distinct workloads. On-demand (standard) VMs have no commitment but the highest per-hour rate. Committed Use Discounts (CUDs) — GCP's equivalent of reserved instances — offer 1- or 3-year commitments for up to 57% savings on N2/C2 families; purchase them via `gcloud compute commitments create`. Spot VMs (formerly preemptible) cut costs by up to 91% but can be reclaimed with a 30-second ACPI signal — ideal for batch jobs, Dataflow pipelines, and GKE node pools with `--spot` flag.

Rightsizing: Cloud Monitoring's Recommender API surfaces machine-type recommendations automatically. Run `gcloud recommender recommendations list --recommender=google.compute.instance.MachineTypeRecommender` to pull idle or over-provisioned instances.

Budget alerts: create programmatic alerts via the Billing API so spikes page your team before the invoice lands. Pair with a `billingAccounts.budgets.create` call to set threshold rules at 50%, 90%, and 100% of forecast.$escape$,
  $escape$# Pull rightsizing recommendations for a project
gcloud recommender recommendations list \
  --project=my-project \
  --location=us-central1-a \
  --recommender=google.compute.instance.MachineTypeRecommender \
  --format="table(name,stateInfo.state,primaryImpact.costProjection.cost.units)"

# Create a billing budget alert at 90% of $500/month
gcloud billing budgets create \
  --billing-account=ABCD-1234-EFGH \
  --display-name="prod-budget" \
  --budget-amount=500USD \
  --threshold-rule=percent=0.9,basis=CURRENT_SPEND \
  --all-projects$escape$,
  $escape$bash$escape$,
