INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cc17ffa8-a299-41d8-a80c-691a8b42b626',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP High Availability — Multi-Region Failover with Global Load Balancing$escape$,
  $escape$GCP's 99.99% SLA for Cloud Load Balancing applies only when you deploy across multiple regions — single-region setups get no SLA guarantee. Use a Global External Application Load Balancer with backend services spanning at least two regions. Traffic is routed via Anycast, so the nearest healthy region handles requests automatically with no DNS TTL delays during failover.

For Compute Engine, deploy managed instance groups (MIGs) in separate zones per region and set `failoverPolicy.failoverRatio` to control when cross-region spillover triggers. For Cloud SQL, enable high-availability (synchronous replication within a zone pair) and add a cross-region read replica promoted manually — or use AlloyDB which supports automatic failover in under 60 seconds.

For GKE, use multi-cluster Ingress with Fleet to distribute traffic across regional clusters. Health checks on the load balancer must use `/healthz` with a 2s timeout and 2 consecutive failures to trigger failover quickly without flapping. Always set `connectionDraining.drainingTimeoutSec` to 30s to avoid dropped in-flight requests during instance removal.$escape$,
  $escape$# Create a global backend service with multi-region failover
gcloud compute backend-services create my-backend \
  --global \
  --protocol=HTTP \
  --health-checks=my-http-check \
  --connection-draining-timeout=30

# Add primary region backend (us-central1 MIG)
gcloud compute backend-services add-backend my-backend \
  --global \
  --instance-group=mig-us-central1 \
  --instance-group-region=us-central1 \
  --balancing-mode=UTILIZATION \
  --max-utilization=0.8

# Add failover region backend (us-east1 MIG)
gcloud compute backend-services add-backend my-backend \
  --global \
  --instance-group=mig-us-east1 \
  --instance-group-region=us-east1 \
  --balancing-mode=UTILIZATION \
  --max-utilization=0.8$escape$,
  $escape$bash$escape$,
