INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1c23c6c4-cbb6-4293-9b27-aa2d61e4d01c',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Cloud CDN — Cache Setup, Invalidation, and Edge Strategy$escape$,
  $escape$GCP Cloud CDN sits in front of Cloud Load Balancing backends (GCS buckets, NEGs, instance groups). Enable it per backend service with `--enable-cdn` and configure cache mode via `--cache-mode=CACHE_ALL_STATIC` (default) or `FORCE_CACHE_ALL` to cache even responses missing `Cache-Control` headers. Set `--default-ttl`, `--max-ttl`, and `--client-ttl` to control edge TTLs independently of origin headers.

For cache keys, use `--cache-key-policy` to include or exclude query strings, headers, and named cookies — critical when serving personalized or A/B-tested content. Cache invalidation is URL-pattern-based via `gcloud compute url-maps invalidate-cdn-cache`. Wildcard patterns like `/assets/*` flush entire paths without touching unrelated content.

For edge caching strategy: serve static assets from GCS with `Cache-Control: public, max-age=31536000, immutable` and use content-hashed filenames. For dynamic API responses, set `Vary: Accept-Encoding, Authorization` carefully — CDN respects `Vary` and splits cache entries per value, which can destroy hit rates if Authorization is included. Use signed URLs or signed cookies for private content at the edge instead.$escape$,
  $escape$# Enable Cloud CDN on an existing backend service
gcloud compute backend-services update my-backend \
  --global \
  --enable-cdn \
  --cache-mode=CACHE_ALL_STATIC \
  --default-ttl=3600 \
  --max-ttl=86400 \
  --client-ttl=600 \
  --cache-key-policy-include-host \
  --cache-key-policy-include-protocol

# Invalidate a path pattern across all edge POPs
gcloud compute url-maps invalidate-cdn-cache my-url-map \
  --path "/assets/*" \
  --global$escape$,
  $escape$bash$escape$,
