INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b1aae3fa-eb2a-4702-9f53-2eadd0b13a39',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Cloud Run & Cloud Functions — Surviving Cold Starts and Timeout Walls$escape$,
  $escape$Cloud Run instances cold-start when no warm container exists — typically 1–4s for Node.js, 3–8s for JVM. Minimum instances (--min-instances) eliminate cold starts at the cost of idle billing. Cloud Functions Gen2 (backed by Cloud Run) inherits the same model. Timeout limits are hard walls: Cloud Run caps at 3600s per request, Cloud Functions Gen2 at 3600s, but Gen1 HTTP functions cap at 540s — critical for long-running data pipelines. Beyond the wall, the request is killed without a response. Stateless design isn't optional — each container instance can serve concurrent requests, and filesystem writes to /tmp are instance-local, ephemeral, and capped at 512MB (configurable up to 32GB on Cloud Run). Use Cloud Storage for shared state, Firestore or Cloud Spanner for transactional state, and Memorystore (Redis) for session/cache. Avoid in-memory singletons that assume request affinity — Cloud Run's concurrency model (up to 1000 req/instance) means multiple requests share the same process simultaneously, not sequentially.$escape$,
  $escape$# Deploy Cloud Run with min instances and extended timeout
gcloud run deploy my-service \
  --image gcr.io/my-project/my-service:latest \
  --min-instances 2 \
  --max-instances 100 \
  --concurrency 80 \
  --timeout 3600 \
  --memory 512Mi \
  --region us-central1 \
  --set-env-vars="INSTANCE_CONNECTION_NAME=my-project:us-central1:my-db"

# Check cold start behavior via Cloud Logging
gcloud logging read 'resource.type="cloud_run_revision" AND textPayload:"Cold Start"' \
  --limit 20 --format json$escape$,
  $escape$bash$escape$,
