INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7940d621-9c03-44e4-b1dc-672ed22271c2',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Cloud Run + Cloudflare Workers — Slash Latency with Edge Routing$escape$,
  $escape$Cloud Run is regional. A service deployed to us-central1 adds 150–300ms RTT for users in Europe or Asia-Pacific — before your code even runs. Cloudflare Workers execute at 300+ PoPs globally, intercepting requests within ~5ms of the user. The pattern: route auth checks, geo-detection, A/B flag evaluation, and cache reads through a Worker, then proxy only cache-misses or authenticated requests to your Cloud Run origin URL. This removes entire round-trips for cacheable responses and offloads JWT verification (using Clerk or Firebase Auth public keys) from your Cloud Run instances. Workers also let you rewrite paths before they hit your Cloud Run service, enabling blue/green traffic splits without touching your GCP Load Balancer config or backend service weights. For latency-sensitive APIs backed by Cloud Spanner or Firestore, this edge layer cuts median P50 latency by 40–60% for globally distributed users — without replicating your Cloud Run services across regions.$escape$,
  $escape$// Cloudflare Worker proxying to GCP Cloud Run with JWT check
export default {
  async fetch(req: Request): Promise<Response> {
    const token = req.headers.get('Authorization')?.split(' ')[1];
    if (!token) return new Response('Unauthorized', { status: 401 });

    // Validate Firebase/Clerk JWT at the edge (no Cloud Run cold start)
    const JWKS_URL = 'https://www.googleapis.com/service_accounts/v1/jwk/securetoken@system.gserviceaccount.com';
    const { default: jose } = await import('jose');
    const JWKS = jose.createRemoteJWKSet(new URL(JWKS_URL));
    await jose.jwtVerify(token, JWKS); // throws on invalid

    // Proxy verified request to regional Cloud Run origin
    const origin = 'https://my-service-abc123-uc.a.run.app';
    return fetch(new Request(origin + new URL(req.url).pathname, req));
  },
};$escape$,
