INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e1343a7e-fbc2-4f34-a357-05b6e37ad15b',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Security Hardening — Encryption, Secrets, WAF, and DDoS in One Stack$escape$,
  $escape$GCP encrypts all data at rest by default using AES-256 via Google's Key Management Service. For tighter control, use Customer-Managed Encryption Keys (CMEK) with Cloud KMS — attach a key ring to Cloud SQL, GCS, or BigQuery at resource creation time. In transit, GCP enforces TLS 1.2+ on all managed services; for internal service mesh traffic, use Anthos Service Mesh with mTLS enforced via `PeerAuthentication` policy set to `STRICT`. Secrets belong in Secret Manager, not env vars — grant access with IAM binding `roles/secretmanager.secretAccessor` scoped to a specific service account, not the default compute SA. For WAF, Cloud Armor security policies attach directly to backend services via the load balancer; use preconfigured ModSecurity rules (OWASP CRS) with `evaluatePreconfiguredExpr('sqli-v33-stable')`. DDoS protection is layered: Google Front End absorbs volumetric attacks globally, while Cloud Armor adaptive protection detects L7 anomalies and auto-suggests rules. Enable it per backend service with `--enable-layer7-ddos-defense`.$escape$,
  $escape$# Attach a Cloud KMS CMEK to a new Cloud SQL instance
gcloud sql instances create prod-db \
  --database-version=POSTGRES_15 \
  --disk-encryption-key=projects/my-project/locations/us-central1/keyRings/prod-ring/cryptoKeys/sql-key

# Grant Secret Manager access to a specific service account
gcloud secrets add-iam-policy-binding db-password \
  --member="serviceAccount:api-sa@my-project.iam.gserviceaccount.com" \
  --role="roles/secretmanager.secretAccessor"

# Enable Cloud Armor adaptive DDoS protection on a backend service
gcloud compute backend-services update my-backend-service \
  --security-policy=prod-armor-policy \
  --global$escape$,
  $escape$bash$escape$,
