INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b02d199a-7a8c-4aa4-9d1f-2cb6c74e3817',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP PaaS vs IaaS — Cloud Run vs GKE vs Railway/Fly.io: Where to Draw the Control Line$escape$,
  $escape$GCP gives you a native PaaS-to-IaaS spectrum before you ever touch Railway or Fly.io. Cloud Run sits at the managed end — push a container, get HTTPS, autoscaling, and IAM-integrated service accounts in seconds, with zero node management. GKE Autopilot sits in the middle: Kubernetes semantics, but Google manages the control plane and node pools. Raw GKE Standard or Compute Engine puts you in full IaaS territory — you own OS patching, networking, and cluster upgrades.

External PaaS like Railway and Fly.io abstract all of this away, but at a cost: you lose VPC-native connectivity to Cloud SQL private IPs, Workload Identity Federation for keyless auth, and fine-grained IAM roles. If your service talks to Memorystore, Pub/Sub, or Vertex AI, staying inside GCP's network boundary eliminates auth complexity and egress charges. Cloud Run with `--vpc-connector` or Direct VPC Egress gives you Railway-level DX while keeping private service connectivity intact. Default to Cloud Run unless you need stateful workloads, custom kernel params, or multi-container pods — then step up to GKE Autopilot before reaching for raw IaaS.$escape$,
  $escape$# Cloud Run deploy — PaaS-level DX, GCP-native control
gcloud run deploy my-service \
  --image us-central1-docker.pkg.dev/my-project/repo/my-service:latest \
  --region us-central1 \
  --network my-vpc \
  --subnet my-subnet \
  --vpc-egress all-traffic \
  --service-account my-service@my-project.iam.gserviceaccount.com \
  --set-env-vars DB_HOST=10.0.0.3 \
  --no-allow-unauthenticated$escape$,
  $escape$bash$escape$,
