INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e8b6adc7-bb19-49fb-a4ce-43ddde600ab7',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Region Selection — Latency, Data Residency, and Compliance$escape$,
  $escape$Picking the wrong GCP region costs you in latency, compliance fines, or both. Start with latency: use `gcloud compute routes list` and GCP's public latency dashboard to benchmark round-trips from your users to candidate regions. For EU users, `europe-west1` (Belgium) and `europe-west4` (Netherlands) consistently outperform `us-central1` by 80–120ms. Data residency is enforced via Organization Policies — set `constraints/gcp.resourceLocations` in your `orgpolicy.yaml` to restrict resource creation to specific locations. For compliance, GDPR workloads must stay in EU regions; HIPAA requires a signed BAA with Google, achievable in any region but typically scoped to `us-central1` or `us-east1` in practice. Use VPC Service Controls with Access Context Manager to enforce perimeter boundaries at the region level. Multi-region Cloud Spanner (`nam6`, `eur3`) gives you high availability without sacrificing residency guarantees. Always check the GCP Products by Region matrix before committing — not all services (e.g., Vertex AI features, Memorystore tiers) are available in every region.$escape$,
  $escape$# Restrict all resources to EU regions via Organization Policy
cat > org_policy.yaml <<EOF
name: projects/MY_PROJECT_ID/policies/gcp.resourceLocations
spec:
  rules:
  - values:
      allowedValues:
      - in:eu-locations
EOF

gcloud org-policies set-policy org_policy.yaml \
  --project=MY_PROJECT_ID

# Verify effective policy
gcloud org-policies describe gcp.resourceLocations \
  --project=MY_PROJECT_ID$escape$,
  $escape$bash$escape$,
