INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2c6b1801-d79b-459d-ad50-430eaa3d9c9b',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Compliance — SOC2, GDPR, and HIPAA Without the Guesswork$escape$,
  $escape$GCP provides built-in compliance controls, but wiring them correctly is your responsibility. For SOC2, enable Cloud Audit Logs (Data Access logs are off by default — enable them per resource via `gcloud projects get-iam-policy` + Org Policy). Use Access Transparency logs if you're on Enterprise tier to audit Google's own access. For GDPR, leverage Data Residency Org Policies (`constraints/gcp.resourceLocations`) to pin resources to EU regions, and use CMEK (Cloud KMS) so you control encryption keys — critical for right-to-erasure: delete the key version, data becomes unreadable. Configure VPC Service Controls to create a data perimeter around BigQuery/GCS, blocking exfiltration even from compromised service accounts. For HIPAA, GCP signs a BAA — but only covered services qualify (Cloud SQL, GKE, BigQuery, etc. — check the HIPAA implementation guide). Enable DLP API to auto-detect and de-identify PHI in GCS and BigQuery before it hits downstream pipelines. Use `CMEK + Cloud HSM` for hardware-backed key management to satisfy HIPAA encryption-at-rest requirements.$escape$,
  $escape$# Lock resources to EU regions (GDPR data residency)
gcloud resource-manager org-policies set-policy \
  --organization=ORG_ID \
  gdpr-location-policy.yaml

# gdpr-location-policy.yaml
# constraint: constraints/gcp.resourceLocations
# listPolicy:
#   allowedValues:
#     - in:eu-locations

# Enable Data Access audit logs for Cloud Storage (SOC2)
gcloud projects get-iam-policy PROJECT_ID --format=json > policy.json
# Add under auditConfigs: service: storage.googleapis.com, logTypes: [DATA_READ, DATA_WRITE]
gcloud projects set-iam-policy PROJECT_ID policy.json

# Scan GCS bucket for PHI (HIPAA)
gcloud dlp jobs create --project=PROJECT_ID \
  --inspect-template=projects/PROJECT_ID/inspectTemplates/hipaa-template \
  --storage-config='{"cloudStorageOptions":{"fileSet":{"url":"gs://your-bucket/**"}}}'$escape$,
  $escape$bash$escape$,
