INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b8331142-a2af-4351-8379-00f4d5477637',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Deployment Models — Blue/Green, Canary, and Rolling Updates on Cloud Run & GKE$escape$,
  $escape$GCP offers first-class support for all three strategies, but the right tool depends on your runtime. On Cloud Run, canary deployments are native: deploy a new revision with --no-traffic, then use --to-revisions to split a percentage. No load balancer config needed. Blue/green is just a traffic flip — shift 0% → 100% to the new revision after validation, with instant rollback via a single gcloud command.

On GKE, rolling updates are controlled by strategy.rollingUpdate in your Deployment spec. Tune maxSurge and maxUnavailable to balance speed vs. availability. Combine with PodDisruptionBudgets to guard against simultaneous node and pod churn during cluster upgrades. True blue/green on GKE means two Deployments + a Service selector swap, or weighted NEG backends behind a Cloud Load Balancing BackendConfig.

Cloud Deploy abstracts all three into a managed delivery pipeline. Define serialPipeline.stages in clouddeploy.yaml, target Cloud Run or GKE clusters, and get canaryDeployment percentage steps, verifyJob hooks, and approval gates with full Audit Log coverage — no custom rollout scripts needed.$escape$,
  $escape$# 1. Deploy new Cloud Run revision — zero traffic
gcloud run deploy my-service \
  --image gcr.io/my-project/my-service:v2 \
  --no-traffic \
  --region us-central1

# 2. Canary: send 10% to new revision
gcloud run services update-traffic my-service \
  --to-revisions my-service-00002-xyz=10,my-service-00001-abc=90 \
  --region us-central1

# 3. Full promotion after validation
gcloud run services update-traffic my-service \
  --to-latest \
  --region us-central1$escape$,
  $escape$bash$escape$,
