INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1ba86e75-0d78-4acc-af9e-93c11779465d',
  '00000000-0000-0000-0000-000000000001',
  $escape$GCP Cost Anomaly Detection — Catch Billing Spikes Before They Hit Your Invoice$escape$,
  $escape$GCP's Cloud Billing anomaly detection uses ML to alert you when spend deviates unexpectedly from your baseline — no threshold config required. Enable it under Billing → Budget & alerts → Anomaly detection. For programmatic control, use the Cloud Billing Budget API to create budgets with `thresholdRules` and Pub/Sub notifications, then trigger Cloud Functions to auto-disable APIs or cap quotas on breach.

For dashboards, Cloud Monitoring's Metrics Explorer exposes `billing/bytes_downloaded`, `compute.googleapis.com/instance/uptime`, and service-level cost metrics. Pair this with Looker Studio connected to the `cloud_billing_export` BigQuery dataset — enable both Standard Usage Cost and Detailed Usage Cost exports in Billing → Billing export. Query `gcp_cost_export.detailed_usage_cost` to break spend down by `resource.name`, `sku.description`, and `labels` for per-team or per-feature attribution. Set up scheduled queries to populate a `daily_cost_summary` table and alert via Cloud Monitoring when 7-day rolling spend exceeds budget thresholds.$escape$,
  $escape$# Create a billing budget with Pub/Sub alert via gcloud
gcloud billing budgets create \
  --billing-account=BILLING_ACCOUNT_ID \
  --display-name="prod-anomaly-guard" \
  --budget-amount=5000USD \
  --threshold-rule=percent=0.5,basis=CURRENT_SPEND \
  --threshold-rule=percent=0.9,basis=CURRENT_SPEND \
  --threshold-rule=percent=1.0,basis=FORECASTED_SPEND \
  --notifications-rule-pubsub-topic=projects/MY_PROJECT/topics/billing-alerts \
  --filter-projects=projects/MY_PROJECT \
  --calendar-period=MONTH$escape$,
  $escape$bash$escape$,
